我的一个工具后端是vllm服务+nginx的负载均衡，但是有的时候经常会报错400 bad request，我不知道为什么。然后报了400之后这个vllm server就会down掉，我希望这个vllm服务可以down掉之后自动重启，我应该怎么样配置？下面是我目前的启动方案：
```shellscript
#!/usr/bin/env bash
set -euo pipefail
# One-click startup for multi-GPU vLLM embedding backends + nginx load balancer.
# Replace MODEL and HOST_IP as needed.
export CUDA_VISIBLE_DEVICES=0,1,2,3
export VLLM_USE_TORCH_COMPILE=0
MODEL="${MODEL:-/mnt/shared-storage-gpfs2/intern-agent-rl/zhaoyibo/search-agent/models/Qwen3-Embedding-8B}"
MODEL_NAME="${MODEL_NAME:-Qwen3-Embedding-8B}"
HOST_IP="${HOST_IP:-10.102.250.78}"
BASE_PORT="${BASE_PORT:-8001}"
NGINX_PORT="${NGINX_PORT:-8000}"
MAX_MODEL_LEN="${MAX_MODEL_LEN:-8192}"
DTYPE="${DTYPE:-float32}"
NUM_GPUS="${NUM_GPUS:-4}"
WORK_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)"
NGINX_CONF="${WORK_DIR}/configs/nginx_embedding.conf"
NGINX_BODY_DIR="${WORK_DIR}/logs/nginx_body"
mkdir -p "${WORK_DIR}/logs"
mkdir -p "${NGINX_BODY_DIR}"
echo "Generating nginx config at ${NGINX_CONF} ..."
cat > "${NGINX_CONF}" <<EOF
worker_processes  1;
events { worker_connections 1024; }
http {
  client_body_temp_path ${NGINX_BODY_DIR} 1 2;
  upstream vllm_embedding_backends {
$(for i in $(seq 0 $((NUM_GPUS - 1))); do
    port=$((BASE_PORT + i))
    echo "    server ${HOST_IP}:${port};"
  done)
  }
  server {
    listen ${NGINX_PORT};
    location /v1/embeddings {
      proxy_pass http://vllm_embedding_backends;
      proxy_http_version 1.1;
      proxy_set_header Connection "";
      proxy_set_header Host \$host;
      proxy_read_timeout 300;
    }
  }
}
EOF
echo "Starting ${NUM_GPUS} vLLM embedding backends ..."
for i in $(seq 0 $((NUM_GPUS - 1))); do
  port=$((BASE_PORT + i))
  log="${WORK_DIR}/logs/vllm_${port}.log"
  CUDA_VISIBLE_DEVICES="${i}" \
  nohup vllm serve "${MODEL}" \
    --served-model-name "${MODEL_NAME}" \
    --host 0.0.0.0 --port "${port}" \
    --task embedding \
    --dtype "${DTYPE}" \
    --max-model-len "${MAX_MODEL_LEN}" \
    > "${log}" 2>&1 &
  echo "  - GPU ${i}: http://${HOST_IP}:${port}/v1/embeddings (log: ${log})"
done
echo "Starting nginx on port ${NGINX_PORT} ..."
nginx -c "${NGINX_CONF}"
echo "Done."
echo "Embedding LB endpoint: http://${HOST_IP}:${NGINX_PORT}/v1/embeddings"
```
下面是我的nginx的config文件：
```properties
# 1. 根据 CPU 核心数自动调整 Worker 数量，处理高并发
worker_processes auto;
# 2. 提高文件描述符上限 (必须大于 worker_connections)
worker_rlimit_nofile 65535;
events {
    # [关键] 大幅提升并发连接数上限
    # 你的需求：1536 seqs * 2 (双向) = 3072。给 20480 留足余量。
    worker_connections 20480;

    # 允许一个 Worker 同时接受多个新连接
    multi_accept on;
    # 使用最高效的 IO 模型
    use epoll;
}
http {
    # 关闭 Access Log 以减少磁盘 IO (训练期间日志量巨大，写入会阻塞)
    access_log off;
    # 只记录错误日志
    error_log /var/log/nginx/error.log warn;
    # 优化文件传输
    sendfile on;
    tcp_nopush on;
    tcp_nodelay on;
    # [关键] 增大 Buffer，避免把 Embedding 请求体 (JSON) 写入临时文件
    # 如果 Body 超过这个大小，Nginx 会写磁盘，导致极慢
    client_body_buffer_size 10m;
    client_max_body_size 20m;

    # 你的路径配置保持不变
    client_body_temp_path /mnt/shared-storage-gpfs2/intern-agent-rl/zhaoyibo/search-agent/logs/nginx_body 1 2;
    upstream vllm_embedding_backends {
        # 负载均衡策略：最少连接数 (比默认的轮询更适合长短不一的推理任务)
        least_conn;
        server 10.102.250.78:8001;
        server 10.102.250.78:8002;
        server 10.102.250.78:8003;
        server 10.102.250.78:8004;
        # [关键] 保持与 vLLM 的长连接池
        # 这里设置 512，意味着每个 Worker 保持 512 个空闲连接
        keepalive 512;
    }
    server {
        listen 8000;

        # 开启 Gzip 可以减少 JSON 传输带宽，但会增加 CPU 消耗。
        # 内网环境下通常带宽足够，建议关闭 Gzip 以降低延迟
        gzip off;
        location /v1/embeddings {
            proxy_pass http://vllm_embedding_backends;
            # HTTP 1.1 支持长连接
            proxy_http_version 1.1;
            # 清除 Connection header，防止 Nginx 关闭上游连接
            proxy_set_header Connection "";

            # 透传 Host
            proxy_set_header Host $host;
            # 超时设置
            proxy_connect_timeout 5s; # 建连应该很快
            proxy_send_timeout 300s;
            proxy_read_timeout 300s;  # 等待 vLLM 推理的时间
        }
    }
}
```
